import { generateText, streamText } from 'ai';
import { createVexMiddleware } from '@vex_dev/sdk';

const vex = createVexMiddleware({
  projectId: 'your-project-id'
});

export async function detectRetrievalQuality(query: string, retrievedChunks: any[]) {
  const scores = retrievedChunks.map(chunk => 
    chunk.embeddingSimilarity || 0
  );
  const avgRelevance = scores.reduce((a, b) => a + b, 0) / scores.length;

  if (avgRelevance < 0.75) {
    vex.capture({
      name: 'low-retrieval-relevance',
      payload: { query, avgRelevance, scores },
      level: 'warning'
    });
  }
  return avgRelevance;
}
