import { countTokens } from 'ai';

export async function detectContextOverflow(context: string[], maxTokens: number = 8000) {
  const totalTokens = await countTokens(context.join('\n'));
  const relevanceRatio = context.filter(c => c.includes('relevant')).length / context.length;

  if (totalTokens > maxTokens && relevanceRatio < 0.6) {
    console.warn(`Context overflow: ${totalTokens} tokens, ${Math.round(relevanceRatio*100)}% relevant`);
    return false;
  }
  return true;
}
