import { streamText } from 'ai';

export async function trackHallucinationDrift({
  query,
  context,
  stream
}: any) {
  let chunkCount = 0;
  let contextMatches = 0;

  for await (const chunk of stream) {
    chunkCount++;
    if (chunk.text && context.some(c => chunk.text.includes(c.slice(0, 50)))) {
      contextMatches++;
    }
  }

  const driftRatio = 1 - (contextMatches / Math.max(chunkCount, 1));
  if (driftRatio > 0.4) {
    console.error(`High hallucination drift: ${Math.round(driftRatio*100)}%`);
  }
}
