import { generateText } from 'ai';

export async function optimizedRAG(query: string, docs: any[]) {
  // Hybrid search: keyword + semantic
  const keywordResults = docs.filter(doc => 
    doc.content.toLowerCase().includes(query.toLowerCase())
  );

  // Semantic search (top 20)
  const semanticResults = await vectorSearch(query, docs, { topK: 20 });

  // Re-rank with metadata filtering
  const reranked = await rerankResults([...keywordResults, ...semanticResults], {
    query,
    filters: { date: { $gte: '2024-01-01' } }
  });

  const context = reranked.slice(0, 5).map(r => r.content).join('\n');

  return generateText({
    model: 'gpt-4o',
    prompt: `Answer using ONLY this context:\n${context}\n\nQuery: ${query}`,
  });
}
