export function createOptimizedChunks(docs: any[]) {
  return docs.flatMap(doc => {
    const sentences = doc.content.split(/[.!?]+/);
    const chunks: any[] = [];

    for (let i = 0; i < sentences.length; i += 3) {
      const chunkText = sentences.slice(i, i + 3).join(' ').trim();
      if (chunkText.length > 100) {
        chunks.push({
          content: chunkText,
          metadata: {
            source: doc.source,
            date: doc.date,
            section: doc.section,
            tokenCount: chunkText.split(' ').length
          }
        });
      }
    }
    return chunks;
  });
}
