export async function qualityGatedStream(query: string) {
  const retrieved = await retrieveDocuments(query);
  const qualityScore = await evaluateRetrievalQuality(query, retrieved);

  if (qualityScore < 0.7) {
    // Fallback to web search or cached answers
    return streamText({
      model: 'gpt-4o',
      prompt: `No good docs found for: ${query}. Search web or use general knowledge.`
    });
  }

  return streamText({
    model: 'gpt-4o',
    system: 'Answer using ONLY these documents',
    messages: [{ role: 'user', content: query }, { role: 'system', content: retrieved.join('\n') }]
  });
}
